59	  const appendToken = useCallback((id: string, token: string) => {
60	    setMessages((prev) =>
61	      prev.map((m) =>
62	        m.id === id ? { ...m, content: m.content + token } : m,
63	      ),
64	    );
65	  }, []);
66	
67	  const runStream = useCallback(
68	    async (historyForServer: ServerMessage[], placeholderId: string) => {
69	      setStatus("streaming");
70	      setLastError(undefined);
71	
72	      const controller = new AbortController();
73	      abortRef.current = controller;
74	
75	      let response: Response;
76	      try {
77	        response = await fetch("/api/chat", {
78	          method: "POST",
79	          headers: { "Content-Type": "application/json" },
80	          body: JSON.stringify({ messages: historyForServer }),
81	          signal: controller.signal,
82	        });
83	      } catch (err) {
84	        abortRef.current = null;
85	        if (controller.signal.aborted) {
86	          updateMessage(placeholderId, { status: "complete" });
87	          setStatus("idle");
88	          return;
89	        }
90	        const detail = err instanceof Error ? err.message : "network error";
91	        updateMessage(placeholderId, { status: "error" });
92	        setLastError(detail);
93	        setStatus("error");
94	        return;
95	      }
96	
97	      if (!response.ok) {
98	        let detail = `request failed (${response.status})`;
99	        try {
100	          const body = (await response.json()) as {
101	            error?: string;
102	            detail?: string;
103	          };
104	          if (typeof body.detail === "string" && body.detail) {
105	            detail = body.detail;
106	          } else if (typeof body.error === "string" && body.error) {
107	            detail = body.error;
108	          }
109	        } catch {
110	          // body was not JSON; use the default detail.
111	        }
112	        if (response.status === 429) {
113	          detail = `Rate limited — ${detail}. Please wait a moment and retry.`;
114	        }
115	        abortRef.current = null;
116	        updateMessage(placeholderId, { status: "error" });
117	        setLastError(detail);
118	        setStatus("error");
119	        return;
