135	            try {
136	              const meta = JSON.parse(frame.data) as ChatMetaPayload;
137	              const citations: Citation[] = (meta.citations ?? []).map(
138	                (c) => ({
139	                  id: c.id,
140	                  chunkId: c.chunkId,
141	                  snippet: c.snippet,
142	                }),
143	              );
144	              updateMessage(placeholderId, { citations });
145	            } catch {
146	              // malformed meta — ignore.
147	            }
148	          } else if (frame.event === "error") {
149	            let detail = "stream error";
150	            try {
151	              const body = JSON.parse(frame.data) as { detail?: string };
152	              if (typeof body?.detail === "string" && body.detail) {
153	                detail = body.detail;
154	              }
155	            } catch {
156	              // ignore
157	            }
158	            abortRef.current = null;
159	            updateMessage(placeholderId, { status: "error" });
160	            setLastError(detail);
161	            setStatus("error");
162	            return;
163	          } else if (frame.event === "done") {
164	            break;
165	          }
166	        }
167	
168	        updateMessage(placeholderId, { status: "complete" });
169	        setStatus("idle");
170	      } catch (err) {
171	        if (controller.signal.aborted) {
172	          updateMessage(placeholderId, { status: "complete" });
173	          setStatus("idle");
174	          return;
175	        }
176	        const detail = err instanceof Error ? err.message : "stream failed";
177	        updateMessage(placeholderId, { status: "error" });
178	        setLastError(detail);
179	        setStatus("error");
180	      } finally {
181	        abortRef.current = null;
182	      }
183	    },
184	    [appendToken, updateMessage],
185	  );
186	
187	  const submit = useCallback(
188	    async (text: string) => {
189	      const trimmed = text.trim();
190	      if (!trimmed) return;
191	      if (abortRef.current) return; // already streaming
192	
193	      const now = Date.now();
194	      const userMsg: ClientChatMessage = {
195	        id: nextId("u"),
196	        role: "user",
197	        content: trimmed,
198	        status: "complete",
199	        createdAt: now,
