1	import { z } from "zod";
2	
3	export const chatMessageSchema = z.object({
4	  role: z.enum(["user", "assistant"]),
5	  content: z.string().min(1).max(4000),
6	});
7	
8	export const chatRequestSchema = z
9	  .object({
10	    messages: z.array(chatMessageSchema).min(1).max(40),
11	    topicHints: z.array(z.string()).optional(),
12	  })
13	  .refine((req) => req.messages[req.messages.length - 1]?.role === "user", {
14	    message: "latest message must have role 'user'",
15	    path: ["messages"],
16	  });
17	
18	export type ChatMessage = z.infer<typeof chatMessageSchema>;
19	export type ChatRequest = z.infer<typeof chatRequestSchema>;
20	
21	export type ChatMetaPayload = {
22	  citations: { id: string; chunkId: string; snippet: string }[];
23	  usage: { inputTokens?: number; outputTokens?: number };
24	  retrievedCount: number;
25	};
26	
27	export type ChatErrorBody = {
28	  error: string;
29	  detail?: string;
30	};
31	
32	/* ---------------------------------------------------------------------------
33	 * Client-side types — used by the useChat hook and chat UI.
34	 * --------------------------------------------------------------------------- */
35	
36	export type Citation = {
37	  id: string;
38	  chunkId: string;
39	  snippet: string;
40	};
41	
42	export type ChatMessageStatus = "complete" | "streaming" | "error";
43	
44	export type ClientChatMessage = {
45	  id: string;
46	  role: "user" | "assistant";
47	  content: string;
48	  citations?: Citation[];
49	  status: ChatMessageStatus;
50	  createdAt: number;
51	};
