1	/**
2	 * POST /api/chat — public, rate-limited, streaming chat over the corpus.
3	 *
4	 * Pipeline:
5	 *   1. zod-validate body
6	 *   2. rate-limit by IP (or "anon" if absent)
7	 *   3. retrieve top-k corpus chunks for the latest user message
8	 *   4. assemble persona + retrieved context into the system prompt
9	 *   5. open the Anthropic stream and pipe tokens out as SSE
10	 *   6. emit a `meta` event with citations + usage when the model is done
11	 *
12	 * Streaming is intentionally held for up to ~200ms while retrieval runs;
13	 * after that the response is flushed token-by-token as soon as Claude emits
14	 * a delta. Sessions are NOT persisted server-side.
15	 */
16	import { NextRequest } from "next/server";
17	
18	import {
19	  AnthropicError,
20	  getAnthropicClient,
21	} from "@/lib/llm/anthropicClient";
22	import { chatRequestSchema, type ChatMetaPayload } from "@/lib/llm/chatTypes";
23	import { buildPersona } from "@/lib/llm/persona";
24	import { assemblePrompt } from "@/lib/llm/promptAssembly";
25	import {
26	  ANON_KEY,
27	  checkRateLimit,
28	  deriveKey,
29	} from "@/lib/llm/rateLimiter";
30	import { retrieve } from "@/lib/llm/retriever";
31	
32	export const runtime = "nodejs";
33	export const dynamic = "force-dynamic";
34	
35	const SSE_HEADERS = {
36	  "Content-Type": "text/event-stream; charset=utf-8",
37	  "Cache-Control": "no-cache, no-transform",
38	  Connection: "keep-alive",
39	  "X-Accel-Buffering": "no",
40	};
41	
42	export async function POST(req: NextRequest): Promise<Response> {
43	  // 1. Parse + validate JSON body.
44	  let body: unknown;
45	  try {
46	    body = await req.json();
47	  } catch {
48	    return jsonError(400, "invalid_json", "request body must be JSON");
49	  }
50	  const parsed = chatRequestSchema.safeParse(body);
51	  if (!parsed.success) {
52	    return jsonError(
53	      400,
54	      "invalid_request",
55	      parsed.error.issues.map((i) => i.message).join("; ")
56	    );
57	  }
58	  const { messages, topicHints } = parsed.data;
59	  const last = messages[messages.length - 1];
60	
61	  // 2. Rate limit.
62	  const fallbackIp =
63	    (req as unknown as { ip?: string | null }).ip ?? null;
64	  const key = deriveKey(req.headers, fallbackIp);
65	  const rl = await checkRateLimit(key);
66	  if (!rl.allowed) {
67	    const retryAfter = Math.max(1, Math.ceil(rl.resetMs / 1000));
68	    return new Response(
69	      JSON.stringify({
70	        error: "rate_limited",
71	        detail:
72	          rl.limited === "day"
73	            ? "daily request limit reached"
74	            : "hourly request limit reached",
75	        remaining: rl.remaining,
76	        retryAfterSeconds: retryAfter,
77	      }),
78	      {
79	        status: 429,
80	        headers: {
81	          "Content-Type": "application/json",
82	          "Retry-After": String(retryAfter),
83	        },
84	      }
85	    );
86	  }
87	
88	  if (key === ANON_KEY) {
89	    // Defensive log so prod can see when the IP-derivation fallback fired.
90	    console.warn("[/api/chat] no IP available; using anon bucket");
91	  }
92	
93	  // 3. Retrieve.
94	  let retrieved: Awaited<ReturnType<typeof retrieve>> = [];
95	  try {
96	    retrieved = await retrieve(last.content, { k: 8, topicHints });
97	  } catch (err) {
98	    console.error("[/api/chat] retrieval failed", err);
99	    retrieved = [];
100	  }
101	
102	  // 4. Assemble.
103	  const assembled = await assemblePrompt({
104	    persona: buildPersona(),
105	    retrieved,
106	    history: messages.slice(0, -1),
107	    userMessage: last.content,
108	  });
109	
110	  let systemPrompt = assembled.system;
111	  if (retrieved.length === 0) {
112	    systemPrompt +=
113	      "\n\nNOTE: No corpus context was retrieved for this query. Answer in the speaker's voice but be explicit that you cannot cite a source for any specific claim about the speaker's life or work.";
114	  }
115	
116	  // 5. Open stream.
117	  let handle;
118	  try {
119	    handle = await getAnthropicClient().streamMessages({
120	      system: systemPrompt,
121	      messages: assembled.messages,
122	    });
123	  } catch (err) {
124	    return anthropicErrorResponse(err);
125	  }
126	
127	  // 6. Pipe SSE.
128	  const meta: ChatMetaPayload = {
129	    citations: assembled.citations,
130	    usage: {},
131	    retrievedCount: retrieved.length,
132	  };
133	
134	  const encoder = new TextEncoder();
135	  const sse = new ReadableStream<Uint8Array>({
136	    async start(controller) {
137	      const send = (event: string, data: string) => {
138	        controller.enqueue(
139	          encoder.encode(`event: ${event}\ndata: ${data}\n\n`)
140	        );
141	      };
142	      try {
143	        for await (const token of handle.tokens) {
144	          send("token", encodeData(token));
145	        }
146	        try {
147	          meta.usage = await handle.finalUsage();
148	        } catch {
149	          // Usage failure shouldn't sink the stream; surface what we have.
150	        }
151	        send("meta", JSON.stringify(meta));
152	        send("done", "[DONE]");
153	      } catch (err) {
154	        const detail = err instanceof Error ? err.message : String(err);
155	        send("error", JSON.stringify({ error: "stream_failed", detail }));
156	      } finally {
157	        controller.close();
158	      }
159	    },
160	    cancel() {
161	      // Client disconnected; no cleanup required because the SDK stream is
162	      // garbage-collected once the for-await loop exits.
163	    },
164	  });
165	
166	  return new Response(sse, { status: 200, headers: SSE_HEADERS });
167	}
168	
169	function encodeData(s: string): string {
170	  // SSE data lines must not contain raw newlines; encode as JSON string so
171	  // the client can JSON.parse() each token cleanly.
172	  return JSON.stringify(s);
173	}
174	
175	function jsonError(status: number, error: string, detail?: string): Response {
176	  return new Response(JSON.stringify({ error, detail }), {
177	    status,
178	    headers: { "Content-Type": "application/json" },
179	  });
180	}
181	
182	function anthropicErrorResponse(err: unknown): Response {
183	  const status =
184	    err instanceof AnthropicError && typeof err.status === "number"
185	      ? err.status
186	      : undefined;
187	  const detail =
188	    err instanceof Error ? err.message : "anthropic request failed";
189	  console.error("[/api/chat] anthropic error", err);
190	  return new Response(
191	    JSON.stringify({
192	      error: "upstream_error",
193	      detail,
194	      upstreamStatus: status,
195	    }),
196	    {
197	      status: 502,
198	      headers: { "Content-Type": "application/json" },
199	    }
200	  );
201	}
