1	/* ---------------------------------------------------------------------------
2	 * useChat — suite 19/P03
3	 * Client-side state machine for the chat conversation. Owns the message list,
4	 * issues SSE requests against /api/chat, progressively appends streamed
5	 * tokens to an assistant placeholder, and surfaces error / rate-limit state
6	 * so the UI can render a retry affordance.
7	 * --------------------------------------------------------------------------- */
8	
9	"use client";
10	
11	import { useCallback, useRef, useState } from "react";
12	
13	import {
14	  type ChatMetaPayload,
15	  type Citation,
16	  type ClientChatMessage,
17	} from "@/lib/llm/chatTypes";
18	import { streamReader } from "@/lib/llm/streamReader";
19	
20	export type ChatStatus = "idle" | "streaming" | "error";
21	
22	export type UseChatReturn = {
23	  messages: ClientChatMessage[];
24	  status: ChatStatus;
25	  submit: (text: string) => Promise<void>;
26	  retry: () => Promise<void>;
27	  clear: () => void;
28	  stopStreaming: () => void;
29	  lastError?: string;
30	};
31	
32	let _idCounter = 0;
33	function nextId(prefix: string): string {
34	  _idCounter += 1;
35	  return `${prefix}-${Date.now().toString(36)}-${_idCounter}`;
36	}
37	
38	type ServerMessage = { role: "user" | "assistant"; content: string };
39	
40	export function useChat(): UseChatReturn {
41	  const [messages, setMessages] = useState<ClientChatMessage[]>([]);
42	  const [status, setStatus] = useState<ChatStatus>("idle");
43	  const [lastError, setLastError] = useState<string | undefined>(undefined);
44	
45	  const abortRef = useRef<AbortController | null>(null);
46	  const lastUserTextRef = useRef<string | null>(null);
47	  const messagesRefSnapshot = useRef<ClientChatMessage[]>([]);
48	  messagesRefSnapshot.current = messages;
49	
50	  const updateMessage = useCallback(
51	    (id: string, patch: Partial<ClientChatMessage>) => {
52	      setMessages((prev) =>
53	        prev.map((m) => (m.id === id ? { ...m, ...patch } : m)),
54	      );
55	    },
56	    [],
57	  );
58	
59	  const appendToken = useCallback((id: string, token: string) => {
60	    setMessages((prev) =>
61	      prev.map((m) =>
62	        m.id === id ? { ...m, content: m.content + token } : m,
63	      ),
64	    );
65	  }, []);
66	
67	  const runStream = useCallback(
68	    async (historyForServer: ServerMessage[], placeholderId: string) => {
69	      setStatus("streaming");
70	      setLastError(undefined);
71	
72	      const controller = new AbortController();
73	      abortRef.current = controller;
74	
75	      let response: Response;
76	      try {
77	        response = await fetch("/api/chat", {
78	          method: "POST",
79	          headers: { "Content-Type": "application/json" },
80	          body: JSON.stringify({ messages: historyForServer }),
81	          signal: controller.signal,
82	        });
83	      } catch (err) {
84	        abortRef.current = null;
85	        if (controller.signal.aborted) {
86	          updateMessage(placeholderId, { status: "complete" });
87	          setStatus("idle");
88	          return;
89	        }
90	        const detail = err instanceof Error ? err.message : "network error";
91	        updateMessage(placeholderId, { status: "error" });
92	        setLastError(detail);
93	        setStatus("error");
94	        return;
95	      }
96	
97	      if (!response.ok) {
98	        let detail = `request failed (${response.status})`;
99	        try {
100	          const body = (await response.json()) as {
101	            error?: string;
102	            detail?: string;
103	          };
104	          if (typeof body.detail === "string" && body.detail) {
105	            detail = body.detail;
106	          } else if (typeof body.error === "string" && body.error) {
107	            detail = body.error;
108	          }
109	        } catch {
110	          // body was not JSON; use the default detail.
111	        }
112	        if (response.status === 429) {
113	          detail = `Rate limited — ${detail}. Please wait a moment and retry.`;
114	        }
115	        abortRef.current = null;
116	        updateMessage(placeholderId, { status: "error" });
117	        setLastError(detail);
118	        setStatus("error");
119	        return;
120	      }
121	
122	      try {
123	        for await (const frame of streamReader(response)) {
124	          if (frame.event === "token") {
125	            let token: string;
126	            try {
127	              token = JSON.parse(frame.data) as string;
128	            } catch {
129	              token = frame.data;
130	            }
131	            if (typeof token === "string" && token.length > 0) {
132	              appendToken(placeholderId, token);
133	            }
134	          } else if (frame.event === "meta") {
135	            try {
136	              const meta = JSON.parse(frame.data) as ChatMetaPayload;
137	              const citations: Citation[] = (meta.citations ?? []).map(
138	                (c) => ({
139	                  id: c.id,
140	                  chunkId: c.chunkId,
141	                  snippet: c.snippet,
142	                }),
143	              );
144	              updateMessage(placeholderId, { citations });
145	            } catch {
146	              // malformed meta — ignore.
147	            }
148	          } else if (frame.event === "error") {
149	            let detail = "stream error";
150	            try {
151	              const body = JSON.parse(frame.data) as { detail?: string };
152	              if (typeof body?.detail === "string" && body.detail) {
153	                detail = body.detail;
154	              }
155	            } catch {
156	              // ignore
157	            }
158	            abortRef.current = null;
159	            updateMessage(placeholderId, { status: "error" });
160	            setLastError(detail);
161	            setStatus("error");
162	            return;
163	          } else if (frame.event === "done") {
164	            break;
165	          }
166	        }
167	
168	        updateMessage(placeholderId, { status: "complete" });
169	        setStatus("idle");
170	      } catch (err) {
171	        if (controller.signal.aborted) {
172	          updateMessage(placeholderId, { status: "complete" });
173	          setStatus("idle");
174	          return;
175	        }
176	        const detail = err instanceof Error ? err.message : "stream failed";
177	        updateMessage(placeholderId, { status: "error" });
178	        setLastError(detail);
179	        setStatus("error");
180	      } finally {
181	        abortRef.current = null;
182	      }
183	    },
184	    [appendToken, updateMessage],
185	  );
186	
187	  const submit = useCallback(
188	    async (text: string) => {
189	      const trimmed = text.trim();
190	      if (!trimmed) return;
191	      if (abortRef.current) return; // already streaming
192	
193	      const now = Date.now();
194	      const userMsg: ClientChatMessage = {
195	        id: nextId("u"),
196	        role: "user",
197	        content: trimmed,
198	        status: "complete",
199	        createdAt: now,
200	      };
201	      const placeholder: ClientChatMessage = {
202	        id: nextId("a"),
203	        role: "assistant",
204	        content: "",
205	        status: "streaming",
206	        createdAt: now + 1,
207	      };
208	
209	      lastUserTextRef.current = trimmed;
210	
211	      // Capture the latest message list synchronously so the request payload
212	      // includes the just-pushed user message — useState updates don't flush
213	      // before the request is built.
214	      const historyForServer: ServerMessage[] = messagesRefSnapshot.current
215	        .filter((m) => m.status === "complete")
216	        .map((m) => ({ role: m.role, content: m.content }));
217	      historyForServer.push({ role: "user", content: trimmed });
218	
219	      setMessages((prev) => [...prev, userMsg, placeholder]);
220	
221	      await runStream(historyForServer, placeholder.id);
222	    },
223	    [runStream],
224	  );
225	
226	  const retry = useCallback(async () => {
227	    if (abortRef.current) return;
228	    const lastText = lastUserTextRef.current;
229	    if (!lastText) return;
230	
231	    let placeholderId = "";
232	    setMessages((prev) => {
233	      const next = [...prev];
234	      while (
235	        next.length > 0 &&
236	        next[next.length - 1].role === "assistant" &&
237	        next[next.length - 1].status !== "complete"
238	      ) {
239	        next.pop();
240	      }
241	      const newPlaceholder: ClientChatMessage = {
242	        id: nextId("a"),
243	        role: "assistant",
244	        content: "",
245	        status: "streaming",
246	        createdAt: Date.now(),
247	      };
248	      placeholderId = newPlaceholder.id;
249	      next.push(newPlaceholder);
250	      return next;
251	    });
252	
253	    const historyForServer: ServerMessage[] = messagesRefSnapshot.current
254	      .filter((m) => m.status === "complete")
255	      .map((m) => ({ role: m.role, content: m.content }));
256	    if (
257	      historyForServer.length === 0 ||
258	      historyForServer[historyForServer.length - 1].role !== "user" ||
259	      historyForServer[historyForServer.length - 1].content !== lastText
260	    ) {
261	      historyForServer.push({ role: "user", content: lastText });
262	    }
263	
264	    await runStream(historyForServer, placeholderId);
265	  }, [runStream]);
266	
267	  const clear = useCallback(() => {
268	    if (abortRef.current) {
269	      abortRef.current.abort();
270	      abortRef.current = null;
271	    }
272	    setMessages([]);
273	    setStatus("idle");
274	    setLastError(undefined);
275	    lastUserTextRef.current = null;
276	  }, []);
277	
278	  const stopStreaming = useCallback(() => {
279	    const ctrl = abortRef.current;
280	    if (!ctrl) return;
281	    ctrl.abort();
282	    abortRef.current = null;
283	    setStatus("idle");
284	  }, []);
285	
286	  return {
287	    messages,
288	    status,
289	    submit,
290	    retry,
291	    clear,
292	    stopStreaming,
293	    lastError,
294	  };
295	}
