8	type Frame = { event: string; data: string };
9	
10	function encodeFrame(f: Frame): Uint8Array {
11	  return encoder.encode(`event: ${f.event}\ndata: ${f.data}\n\n`);
12	}
13	
14	function streamFrom(frames: Frame[]): Response {
15	  const stream = new ReadableStream<Uint8Array>({
16	    start(controller) {
17	      for (const f of frames) {
18	        controller.enqueue(encodeFrame(f));
19	      }
20	      controller.close();
21	    },
22	  });
23	  return new Response(stream, {
24	    status: 200,
25	    headers: { "Content-Type": "text/event-stream" },
26	  });
27	}
28	
29	function holdingStream(initial: Frame[]): {
30	  response: Response;
31	  release: () => void;
32	  errorOut: (err: unknown) => void;
33	} {
34	  let release!: () => void;
35	  let errorOut!: (err: unknown) => void;
36	  const stream = new ReadableStream<Uint8Array>({
37	    start(controller) {
38	      for (const f of initial) {
39	        controller.enqueue(encodeFrame(f));
40	      }
41	      release = () => {
42	        try {
43	          controller.close();
44	        } catch {
45	          // already closed
46	        }
47	      };
48	      errorOut = (err) => {
49	        try {
50	          controller.error(err);
51	        } catch {
52	          // already closed/errored
53	        }
54	      };
55	    },
56	  });
57	  const response = new Response(stream, {
58	    status: 200,
59	    headers: { "Content-Type": "text/event-stream" },
60	  });
61	  return { response, release, errorOut };
62	}
