63	async function readSSE(res: Response): Promise<{
64	  events: { event: string; data: string }[];
65	  raw: string;
66	}> {
67	  const text = await res.text();
68	  const events: { event: string; data: string }[] = [];
69	  const blocks = text.split("\n\n").filter(Boolean);
70	  for (const block of blocks) {
71	    const lines = block.split("\n");
72	    let event = "message";
73	    const dataLines: string[] = [];
74	    for (const line of lines) {
75	      if (line.startsWith("event: ")) event = line.slice("event: ".length);
76	      else if (line.startsWith("data: ")) dataLines.push(line.slice("data: ".length));
77	    }
78	    events.push({ event, data: dataLines.join("\n") });
79	  }
80	  return { events, raw: text };
81	}
