6	export function recordRecent(path: string, title?: string) {
7	  if (typeof window === "undefined") return;
8	  try {
9	    const cur: { path: string; title?: string }[] = JSON.parse(sessionStorage.getItem(KEY) ?? "[]");
10	    const next = [{ path, title }, ...cur.filter((x) => x.path !== path)].slice(0, MAX);
11	    sessionStorage.setItem(KEY, JSON.stringify(next));
12	  } catch {}
13	}
