15	export function recentCommands(): Command[] {
16	  if (typeof window === "undefined") return [];
17	  let recent: { path: string; title?: string }[] = [];
18	  try { recent = JSON.parse(sessionStorage.getItem(KEY) ?? "[]"); } catch {}
19	  return recent.map((r, i) => ({
20	    id: `nav.recent.${i}`,
21	    kind: "nav" as const,
22	    section: "Navigate" as const,
23	    title: `Recent: ${r.title ?? r.path}`,
24	    context: r.path,
25	    keywords: ["recent", r.path.replace(/[/-]/g, " ")],
26	    run: ({ router, close }) => { router.push(r.path); close(); },
27	  }));
28	}
